const nodesRender = (nodes) => (cb) => {
  const nodelist = [];
  const loop = (list) => {
    list.forEach(node => {
      nodelist.push(node);
      if (node?.children?.length > 0) {
        loop(node.children);
      }
    });
  };
  if (cb && typeof cb === 'function') {
    loop(nodes && [nodes] || []);
    return nodelist.map(cb);
  }
};
class CompactBoxTree extends Component {
  constructor() {
    super();
  }
  state = {
    data: {},
  }
  componentDidMount() {
    let root = document.getElementById('dag-canvas');
    let that = this;
    this.canvas = new TreeCanvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: false,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          type: 'AdvancedBezier',
          arrow: true
        }
      },
      layout: {
        type: 'compactBox',
        options: {
          direction: 'LR',
          getHeight(d) {
            return 60;
          },
          getWidth(d) {
            // console.log(d);
            // console.log(this);
            let node = that.canvas.getNode(d.id);
            if (node) {
              return $(node.dom).width();
            } else {
              return 100;
            }
            // return 180;
          },
          getHGap(d) {
            return 60;
          },
          getVGap(d) {
            return 20;
          },
        }
      }
    });
    this.canvas.draw(mockData, {}, () => {
      this.setState({
        data: mockData
      }, () => {
        this.canvas.focusCenterWithAnimate();
        this.canvas.redraw();
      });
    });
    let _tmpNum = 100;
    this.canvas.on('events', (data) => {
      if (data.type === 'custom:addSubNode') {
        // addNode，removeNode可以还需要重写下
        this.canvas.addNode({
          id: _tmpNum.toString(),
          text: `我是id为${_tmpNum}的节点`,
          parent: data.data.parent,
          Class: Node,
          endpoints: [{
            id: 'left',
            orientation: [-1, 0],
            pos: [0, 0.5]
          }, {
            id: 'right',
            orientation: [1, 0],
            pos: [0, 0.5]
          }],
        });
        this.canvas.addEdge({
          id: this.canvas.edges.length.toString(),
          source: 'right',
          target: 'left',
          sourceNode: data.data.parent,
          targetNode: (_tmpNum++).toString(),
          type: 'endpoint'
        });
        this.canvas.redraw();
      }
    });
  }
  render() {
    return (
      <div className='ruleTree-page'>
        {
          nodesRender(this.state.data.nodes)(
            node => {
              const div = document.getElementById(node.id);
              if (!div) {
                return null;
              }
              return ReactDom.createPortal(
                <Custom key={node.id} node={node} canvas={this.canvas} />,
                div
              );
            }
          )
        }
        <div className="ruleTree-canvas" id="dag-canvas" />
      </div>
    );
  }
}

